const d = $input.first().json;

let score = 0;
if (d.website && d.website.trim().length > 0) score += 1;
if (d.socials && d.socials.trim().length > 0) score += 1;
if (d.businessNiche && d.businessNiche.trim().length > 20) score += 1;

// Niche → subgroup matching (aligned with whatsapp-groups.ts)
const niche = (d.businessNiche || '').toLowerCase();
const subgroupMap = [
  { key: 'tech',       envVar: 'WA_GROUP_TECH_INVITE',       keywords: ['saas','software','developer','tech','coding','app','startup','api','engineer','devops','ai','ml'] },
  { key: 'marketing',  envVar: 'WA_GROUP_MARKETING_INVITE',  keywords: ['marketing','growth','seo','ads','facebook ads','google ads','funnel','copywriting','branding','pr','influencer'] },
  { key: 'ecommerce',  envVar: 'WA_GROUP_ECOMMERCE_INVITE',  keywords: ['ecommerce','e-commerce','shopify','amazon','dropship','fba','product','dtc','physical product','wholesale','retail'] },
  { key: 'media',      envVar: 'WA_GROUP_MEDIA_INVITE',      keywords: ['content','youtube','podcast','creator','newsletter','writer','blogger','video','media','tiktok','instagram'] },
  { key: 'agency',     envVar: 'WA_GROUP_AGENCY_INVITE',     keywords: ['agency','freelance','consulting','service','coach','coaching','done for you','outsource'] },
  { key: 'finance',    envVar: 'WA_GROUP_FINANCE_INVITE',    keywords: ['investor','investing','finance','fund','fintech','crypto','trading','venture','angel','wealth'] },
];

const matchedSubgroups = subgroupMap.filter(g => g.keywords.some(kw => niche.includes(kw)));

return [{ json: { ...d, qualificationScore: score, autoApprove: score >= 2, matchedSubgroups } }];
